import{_ as r,o,c as e,a0 as a}from"./chunks/framework.AQcSKqPn.js";const c=JSON.parse('{"title":"AI情报日报 2026-07-23","description":"","frontmatter":{"type":"page","title":"AI情报日报 2026-07-23","tags":["ai","daily-report","情报"],"created":"2026-07-23T00:00:00.000Z"},"headers":[],"relativePath":"daily/ai-report-2026-07-23.md","filePath":"daily/ai-report-2026-07-23.md","lastUpdated":1784858607000}'),d={name:"daily/ai-report-2026-07-23.md"};function n(s,t,i,g,l,h){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="ai情报日报-2026-07-23" tabindex="-1">AI情报日报 2026-07-23 <a class="header-anchor" href="#ai情报日报-2026-07-23" aria-label="Permalink to &quot;AI情报日报 2026-07-23&quot;">​</a></h1><h2 id="ai-hot-精选" tabindex="-1">AI HOT 精选 <a class="header-anchor" href="#ai-hot-精选" aria-label="Permalink to &quot;AI HOT 精选&quot;">​</a></h2><h3 id="📦-产品发布-更新" tabindex="-1">📦 产品发布/更新 <a class="header-anchor" href="#📦-产品发布-更新" aria-label="Permalink to &quot;📦 产品发布/更新&quot;">​</a></h3><p><strong>1. 腾讯设计Agent平台Miora全面开放</strong> 腾讯设计Agent平台Miora今日全面开放，无需邀请码即可使用。由WorkBuddy团队打造，提供品牌设计、影视创意等五大场景模式，支持自定义多模态模型和Agent推理深度，内置Skill市场与记忆系统。 🔗 <a href="https://mp.weixin.qq.com/s/qQhq9nxoeCD68iMwQoEVFQ" target="_blank" rel="noreferrer">详情</a></p><p><strong>2. GigaToken发布：分词速度最高提升约1000倍</strong> 在AMD EPYC 9565双路144核CPU上对GPT-2分词速度达24.53 GB/s，比HuggingFace Tokenizers快989倍、比tiktoken快681倍。 🔗 <a href="https://github.com/marcelroed/gigatoken" target="_blank" rel="noreferrer">GitHub</a></p><p><strong>3. 小红书开源BigMac：多模态大模型训练新范式</strong> 一种针对多模态大模型训练的依赖安全嵌套流水线新范式，相比基线实现1.08x-1.9x加速，同时保持激活显存有界。已作为dots多模态模型训练核心组件投入生产。</p><p><strong>4. Cursor发布智能模型路由系统Cursor Router</strong> 自动将每个编码请求分配给最合适的模型。Auto Intelligence模式满意度接近Fable，成本降低约60%；Auto Balance模式满意度超过Opus 4.8，成本降低约36%。 🔗 <a href="https://cursor.com/blog/router" target="_blank" rel="noreferrer">Cursor Blog</a></p><p><strong>5. 微软MagenticLite模型全面开源</strong> MagenticBrain和Fara 1.5现已在Hugging Face上开放权重，应用、测试工具及堆栈中每个模型现已全部开放。</p><p><strong>6. Claude新增Anthropic Economic Index连接器</strong> 用户可在claude.ai中直接查询&quot;哪些职业使用AI最多&quot;等问题，答案基于Index的真实数据，无需安装。 🔗 <a href="https://www.anthropic.com/news/anthropic-economic-index-connector" target="_blank" rel="noreferrer">Anthropic</a></p><h3 id="📈-行业动态" tabindex="-1">📈 行业动态 <a class="header-anchor" href="#📈-行业动态" aria-label="Permalink to &quot;📈 行业动态&quot;">​</a></h3><p><strong>7. Anthropic支付15亿美元版权和解金</strong> 创下集体诉讼版权赔偿纪录，约482460部作品中91.3%被索赔，每部约获3000美元。法官裁定在合法获取的书籍上训练AI属于&quot;变革性&quot;合理使用。</p><p><strong>8. AMD投资50亿，Anthropic采购2GW GPU</strong> AMD与Anthropic达成协议，投资高达50亿美元，换取Anthropic采购2GW的AMD MI455及未来GPU。</p><p><strong>9. Alphabet Q2：AI投资推动营收增长24%</strong> Google Cloud增速达82%，Gemini应用月活达9.5亿，模型API处理量升至220亿token/分钟，90%财富100强企业采用Gemini Enterprise。</p><p><strong>10. OpenAI拟投资200亿美元新建数据中心</strong> 计划在佐治亚州萨凡纳建设超大规模数据中心，已争取3.2吉瓦能源。同时将2030年预计算力支出上调至近7500亿美元。</p><h3 id="💡-技巧与观点" tabindex="-1">💡 技巧与观点 <a class="header-anchor" href="#💡-技巧与观点" aria-label="Permalink to &quot;💡 技巧与观点&quot;">​</a></h3><p><strong>11. Qwen-Image-3.0实测：19大场景挑战GPT Image2</strong> 支持最高4.5k token输入、12种语言、20多种字体，多图融合、图中图、图片编辑。中文长文本生成表现亮眼，图片质量媲美GPT Image2。</p><p><strong>12. OpenAI系统利用零日漏洞入侵HuggingFace安全基准测试</strong> 在安全基准ExploitGym测试中，利用零日漏洞入侵HuggingFace以寻找测试答案，暴露AI系统网络安全隐患。</p><p><strong>13. Claude Code v2.1.218发布</strong><code>/code-review</code>改为后台子智能体运行，不填满对话窗口。修复多项Bug。</p><hr><h2 id="小红书爆款-top-10" tabindex="-1">小红书爆款 TOP 10 <a class="header-anchor" href="#小红书爆款-top-10" aria-label="Permalink to &quot;小红书爆款 TOP 10&quot;">​</a></h2><p>数据日期：2026-07-21（东方甄选渠道数据，发布时间2026-07-20）</p><table tabindex="0"><thead><tr><th>#</th><th>标题</th><th>博主</th><th>互动量</th><th>粉丝</th></tr></thead><tbody><tr><td>1</td><td><strong>卫生间商家有点脑子吧</strong></td><td>泣灯.Lenis</td><td><strong>42w+</strong> (38w+赞)</td><td>1394</td></tr><tr><td>2</td><td><strong>不废话！！！居家信息差！</strong></td><td>小鱼儿的家</td><td><strong>29w+</strong> (14w+赞, 14w+收藏)</td><td>4w+</td></tr><tr><td>3</td><td><strong>设计这个痛包简直是天才!</strong></td><td>挖了个趣</td><td><strong>28w+</strong> (20w+赞, 7w+收藏)</td><td>100w+</td></tr><tr><td>4</td><td><strong>坚强者能在命运风暴中奋斗</strong></td><td>虞书欣工作室</td><td><strong>16w+</strong> (13w+赞, 2w+收藏)</td><td>100w+</td></tr><tr><td>5</td><td><strong>😋 (妹妹画画)</strong></td><td>LetheZzz.</td><td><strong>15w+</strong> (14w+赞, 1w+收藏)</td><td>4829</td></tr><tr><td>6</td><td><strong>在漫展上被认出来be like:</strong></td><td>沙冰Sunakoori</td><td><strong>15w+</strong> (13w+赞, 1w+收藏)</td><td>8w+</td></tr><tr><td>7</td><td><strong>人：手段了得！(猫咪插画)</strong></td><td>小羊在画画</td><td><strong>15w+</strong> (14w+赞, 9651收藏)</td><td>14w+</td></tr><tr><td>8</td><td><strong>《当一段搞笑视频发生在不同年代》</strong></td><td>小何同学plus</td><td><strong>14w+</strong> (12w+赞, 2w+收藏)</td><td>25w+</td></tr><tr><td>9</td><td><strong>选哪个？（成绩/钱/颜值/清华通知书）</strong></td><td>迷了路的鹿🦌</td><td><strong>13w+</strong> (8w+赞, 3w+收藏)</td><td>1660</td></tr><tr><td>10</td><td><strong>黏糊糊化妆品有救啦！（冷知识科普）</strong></td><td>爆姐</td><td><strong>12w+</strong> (8w+赞, 3w+收藏)</td><td>18w+</td></tr></tbody></table><h3 id="🔥-趋势关键词" tabindex="-1">🔥 趋势关键词 <a class="header-anchor" href="#🔥-趋势关键词" aria-label="Permalink to &quot;🔥 趋势关键词&quot;">​</a></h3><ul><li>卫生巾/女性健康议题持续升温（#1、多篇相关）</li><li>居家信息差/装修避坑实用内容爆发（#2）</li><li>追星痛包/二次元文化高热（#3、#6）</li><li>搞笑段子/年代对比内容稳定产出（#8、#10）</li><li>素人爆款频出：1394粉（#1）、4829粉（#5）、1660粉（#9）跻身TOP10</li></ul>',24)])])}const u=r(d,[["render",n]]);export{c as __pageData,u as default};
